// ===== OUTIL RECHERCHE BIENS IMMOBILIERS =====
// Accès complet à TOUS les champs de la table locaux Supabase

const SUPABASE_URL = 'https://udyfhzyvalansmhkynnc.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InVkeWZoenl2YWxhbnNtaGt5bm5jIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTE5NjM1NywiZXhwIjoyMDg2NzcyMzU3fQ.XToUDvcD-crlO0bA8HuJ5g1GjhqTl790fHG6H8bujAk';

try {
  let q = '';
  if (typeof query !== 'undefined') q = query || '';
  else if (typeof $input !== 'undefined' && $input.first() && $input.first().json) q = $input.first().json.query || '';

  q = String(q).toLowerCase().trim();

  const SELECT_FIELDS = [
    'id', 'ref_bien', 'type_de_bien', 'type_offre', 'zone_geographique', 'commune',
    'quartier', 'prix', 'chambre', 'meubles', 'caracteristiques', 'telephone_bien',
    'telephone_expediteur', 'expediteur', 'publie_par', 'disponible', 'status',
    'groupe_whatsapp_origine', 'lien_image', 'message_initial', 'date_publication',
    'date_expiration', 'publication_id'
  ].join(',');

  const filters = [];

  if (!q.includes('non disponible') && !q.includes('vendu') && !q.includes('loué')) {
    filters.push('disponible=eq.Oui');
  }

  const communes = [
    { variants: ['cocody'], value: 'Cocody' },
    { variants: ['yopougon', 'yopo'], value: 'Yopougon' },
    { variants: ['marcory'], value: 'Marcory' },
    { variants: ['koumassi'], value: 'Koumassi' },
    { variants: ['treichville', 'treiche'], value: 'Treichville' },
    { variants: ['plateau'], value: 'Plateau' },
    { variants: ['adjamé', 'adjame'], value: 'Adjamé' },
    { variants: ['abobo'], value: 'Abobo' },
    { variants: ['attécoubé', 'attecoube'], value: 'Attécoubé' },
    { variants: ['port-bouët', 'port-bouet', 'portbouet'], value: 'Port-Bouët' },
    { variants: ['bingerville'], value: 'Bingerville' },
    { variants: ['songon'], value: 'Songon' },
    { variants: ['anyama'], value: 'Anyama' },
    { variants: ['grand-bassam', 'bassam'], value: 'Grand-Bassam' },
    { variants: ['assinie'], value: 'Assinie' }
  ];
  const communeTrouvee = communes.find(c => c.variants.some(v => q.includes(v)));
  if (communeTrouvee) {
    filters.push('commune=ilike.*' + encodeURIComponent(communeTrouvee.value) + '*');
  }

  const typesBien = ['villa', 'appartement', 'studio', 'duplex', 'triplex', 'maison', 'terrain', 'bureau', 'magasin', 'boutique', 'local', 'garage', 'immeuble', 'chambre'];
  const typeTrouve = typesBien.find(t => q.includes(t));
  if (typeTrouve) {
    filters.push('type_de_bien=ilike.*' + encodeURIComponent(typeTrouve) + '*');
  }

  if (q.includes('vente') || q.includes('vendre') || q.includes('achat') || q.includes('acheter') || q.includes('céder')) {
    filters.push('type_offre=eq.Vente');
  } else if (q.includes('location') || q.includes('louer') || q.includes('locat') || q.includes('bail') || q.includes('mensuel')) {
    filters.push('type_offre=eq.Location');
  }

  if (q.includes('meublé') || q.includes('meuble')) {
    filters.push('meubles=eq.true');
  }

  const refMatch = q.match(/([a-z]{2,3}[-_][a-z]{2,3}[-_][a-zA-Z0-9]{4,10})/i);
  if (refMatch) {
    filters.push('ref_bien=ilike.*' + encodeURIComponent(refMatch[1].toUpperCase()) + '*');
  }

  const quartiersConnus = ['angré', 'angre', '2 plateaux', 'deux plateaux', 'riviera', 'bonoumin', 'attoban', 'm’badon', 'mbadon', 'niangon', 'orly', 'campement', 'zone 4', 'zone4', 'solibra', 'remblai', 'iti', 'biabou', 'port-bouët 1', 'cite', 'sicogi', 'epse', 'comoe'];
  const quartierTrouve = quartiersConnus.find(qt => q.includes(qt));
  if (quartierTrouve) {
    filters.push('quartier=ilike.*' + encodeURIComponent(quartierTrouve) + '*');
  }

  const chambreMatch = q.match(/(\d+)\s*(?:pièces?|chambres?|ch\b)/);
  if (chambreMatch) {
    filters.push('chambre=eq.' + chambreMatch[1]);
  }

  const baseUrl = SUPABASE_URL + '/rest/v1/locaux';
  const queryParts = [...filters, 'select=' + SELECT_FIELDS, 'order=date_publication.desc', 'limit=15'];
  const url = baseUrl + '?' + queryParts.join('&');

  const response = await fetch(url, {
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json'
    }
  });

  if (!response.ok) {
    const errText = await response.text();
    return 'Aucun résultat (erreur interne): ' + errText;
  }

  const biens = await response.json();

  if (!biens || biens.length === 0) {
    return 'Aucun bien immobilier disponible ne correspond à ta demande exacte ("' + q + '"). Propose à l\'utilisateur de faire une demande plus générale (ex: retirer le quartier ou modifier le type de bien).';
  }

  const resultats = biens.map(b => {
    const meuble = (b.meubles === true || b.meubles === 'Oui') ? ' | ✅ Meublé' : ' | ❌ Non meublé';
    const chambres = b.chambre ? b.chambre + ' pièce(s)' : '';
    const image = b.lien_image ? '🖼️ Image: ' + b.lien_image : '';
    const datePubli = b.date_publication ? new Date(b.date_publication).toLocaleDateString('fr-FR') : '';
    const groupe = b.groupe_whatsapp_origine ? 'Groupe: ' + b.groupe_whatsapp_origine : '';

    return [
      '---',
      '🏠 *' + (b.ref_bien || 'N/A') + '* | ' + (b.type_offre || '') + ' | ' + (b.type_de_bien || ''),
      '📍 ' + [b.commune, b.quartier, b.zone_geographique].filter(Boolean).join(', '),
      '💰 Prix: ' + (b.prix || 'Non communiqué'),
      '🛏️ Pièces: ' + chambres + meuble,
      '📝 Caractéristiques: ' + (b.caracteristiques ? b.caracteristiques.substring(0, 100) + '...' : 'Non précisé'),
      '📞 Contact: ' + (b.telephone_bien || b.telephone_expediteur || 'Non disponible'),
      datePubli ? '📅 Date: ' + datePubli : '',
      groupe,
      image
    ].filter(Boolean).join('\n');
  }).join('\n\n');

  return 'Résultats (' + biens.length + ' bien(s) trouvé(s)):\n\n' + resultats + '\n\nDis au client: [Pour une visite, citez le REF du bien]';

} catch (err) {
  return 'Outil indisponible pour le moment suite à une erreur: ' + err.message + '. Dis-le poliment au client.';
}
